1	export type Cell = [number, number];
2	
3	const NEIGHBOR_OFFSETS: ReadonlyArray<Cell> = [
4	  [-1, -1], [-1, 0], [-1, 1],
5	  [ 0, -1],          [ 0, 1],
6	  [ 1, -1], [ 1, 0], [ 1, 1],
7	];
8	
9	const cellKey = ([x, y]: Cell): string => `${x},${y}`;
10	
11	const survives = (isAlive: boolean, neighbors: number): boolean =>
12	  neighbors === 3 || (isAlive && neighbors === 2);
13	
14	export function nextGeneration(cells: Cell[]): Cell[] {
15	  const alive = new Set(cells.map(cellKey));
16	  const neighborCounts = new Map<string, { cell: Cell; count: number }>();
17	
18	  for (const [x, y] of cells) {
19	    for (const [dx, dy] of NEIGHBOR_OFFSETS) {
20	      const neighbor: Cell = [x + dx, y + dy];
21	      const k = cellKey(neighbor);
22	      const entry = neighborCounts.get(k);
23	      if (entry) entry.count++;
24	      else neighborCounts.set(k, { cell: neighbor, count: 1 });
25	    }
26	  }
27	
28	  const result: Cell[] = [];
29	  for (const [k, { cell, count }] of neighborCounts) {
30	    if (survives(alive.has(k), count)) result.push(cell);
31	  }
32	  return result;
33	}
34

1	import { describe, it, expect } from "vitest";
2	import { nextGeneration } from "./game-of-life.js";
3	
4	describe("Game of Life - Next Generation", () => {
5	  it("should return empty array when given empty input", () => {
6	    expect(nextGeneration([])).toEqual([]);
7	  });
8	  it("should kill a single live cell (underpopulation)", () => {
9	    expect(nextGeneration([[0, 0]])).toEqual([]);
10	  });
11	  it("should kill two adjacent cells with only one neighbor each (underpopulation)", () => {
12	    expect(nextGeneration([[0, 1], [1, 1]])).toEqual([]);
13	  });
14	  it("should keep a block (2x2) stable (survival with 3 neighbors)", () => {
15	    const block: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1]];
16	    const result = nextGeneration(block);
17	    expect(result.sort()).toEqual(block.sort());
18	  });
19	  it("should kill an overpopulated cell with more than 3 neighbors", () => {
20	    // 2x3 block - middle row cells have 5 neighbors each, must die from overpopulation
21	    const input: [number, number][] = [[0, 0], [1, 0], [0, 1], [1, 1], [0, 2], [1, 2]];
22	    const result = nextGeneration(input);
23	    // Middle row (y=1) should not include the original (0,1) or (1,1) - they died from overpopulation
24	    expect(result).not.toContainEqual([0, 1]);
25	    expect(result).not.toContainEqual([1, 1]);
26	  });
27	  it("should birth a dead cell with exactly 3 live neighbors (reproduction)", () => {
28	    // L-shape: 3 cells with (1,1) dead surrounded by 3 alive neighbors -> birth
29	    const input: [number, number][] = [[0, 0], [1, 0], [0, 1]];
30	    const result = nextGeneration(input);
31	    expect(result).toContainEqual([1, 1]);
32	  });
33	  it("should oscillate a vertical blinker to horizontal", () => {
34	    const vertical: [number, number][] = [[0, 0], [0, 1], [0, 2]];
35	    const expected: [number, number][] = [[-1, 1], [0, 1], [1, 1]];
36	    const sortByCoord = (a: [number, number], b: [number, number]) =>
37	      a[0] - b[0] || a[1] - b[1];
38	    expect([...nextGeneration(vertical)].sort(sortByCoord)).toEqual(
39	      [...expected].sort(sortByCoord),
40	    );
41	  });
42	  it.todo("should handle negative coordinates correctly");
43	});
